import{_ as t,c as o,o as s,a9 as e}from"./chunks/framework.mqRhhfDZ.js";const a="/ning-notes/assets/css.CSLOxsVm.jpg",m=JSON.parse('{"title":"选择器优先级","description":"","frontmatter":{},"headers":[],"relativePath":"front-end/css3/base/选择器优先级.md","filePath":"front-end/css3/base/选择器优先级.md","lastUpdated":1780308897000}'),n={name:"front-end/css3/base/选择器优先级.md"},r=e('<h1 id="选择器优先级" tabindex="-1">选择器优先级 <a class="header-anchor" href="#选择器优先级" aria-label="Permalink to &quot;选择器优先级&quot;">​</a></h1><p>一般情况下，选择器的优先级为</p><blockquote><p>!important 行内 &gt; ID 选择器 &gt; 类选择器 &gt; 元素选择器 &gt; 通配选择器</p><p>相同级别的选择器，显示最后面的样式。</p></blockquote><h2 id="css-权重" tabindex="-1">CSS 权重 <a class="header-anchor" href="#css-权重" aria-label="Permalink to &quot;CSS 权重&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">详细描述</p><ol><li><p>计算方式：每个选择器，都可以算出一组权重，格式为（a,b,c)</p><blockquote><p>格式: (a, b, c)</p><blockquote><p>a: <strong>ID</strong> 选择器的个数</p><p>b: <strong>类、伪类、属性</strong> 选择器的个数</p><p>c: <strong>元素、伪元素</strong> 选择器的个数</p></blockquote></blockquote></li><li><p>比较规则：按照<strong>从左到右</strong>的顺序，依次比较大小，当前位胜出后，后面的不再对比，例如：</p><blockquote><p>(1,0,0) &gt; (0,2,2)</p><p>(1,1,0) &gt; (1,0,3)</p><p>(1,1,3) &gt; (1,1,2)</p></blockquote></li><li><p>特殊规则：</p><ul><li><strong>行内样式</strong>权重大于<strong>所有选择器</strong></li><li><strong>!important</strong>的权重，大于<strong>行内样式</strong>，大于<strong>所有选择器，权重最高！</strong></li></ul></li></ol></div><p><img src="'+a+'" alt="css"></p><ul><li>在 vscode 中，鼠标悬浮在样式上，会弹出来显示选择器、权重。</li></ul>',7),c=[r];function l(p,i,_,g,d,u){return s(),o("div",null,c)}const h=t(n,[["render",l]]);export{m as __pageData,h as default};
